VALUES
  ('optometrist-moex-00234', 'optometrist', 'optometrist-moex-114-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '比較以球面為基礎的鏡片（sphericallybasedlenses）、非球面（asphericalenses）和非複曲面鏡片（atoriclenses） 在球柱鏡上的結構差異，下列敘述何者正確？', '["以球面為基礎的鏡片製造上前表面為複曲面（toric），後表面為球面", "非球面製造上前表面為複曲面（toric），後表面為非球面", "非球面製造上前表面為球面，後表面為複曲面（toric）", "非複曲面鏡片有多種製作方式，以成品單光鏡：前表面為球面，後表面為非複曲面（atoric）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "b457f6524dd3", "answer_pdf_sha1": "ba1c7467242c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00235', 'optometrist', 'optometrist-moex-114-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '鏡片材料有許多種，以下幾種材料請根據阿貝數由高至低排列：①皇冠玻璃  ②聚碳酸酯  ③Trivex鏡片', '["高折射率塑膠  ⑤高折射率玻璃", "", "⑤", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "b457f6524dd3", "answer_pdf_sha1": "ba1c7467242c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 33, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00236', 'optometrist', 'optometrist-moex-114-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '多層膜鏡片的鏡片表面有不同的反射光澤，稱為抗反射膜的反射光殘留色，下列敘述何者錯誤？', '["鏡片前後表面的中央與邊緣部分顏色會有差異", "反射光呈現淺棕黃色，則表示抗反射膜厚度過厚（>139nm）", "鏡片凸面與凹面的曲率不同，也會產生差異", "鏡片前後兩表面，無法同時蒸鍍也會有誤差"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "b457f6524dd3", "answer_pdf_sha1": "ba1c7467242c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00237', 'optometrist', 'optometrist-moex-114-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '在鏡片表面鍍一層氟化鎂（n=1.38）作為抗反射膜，提高光的波長500nm的穿透率，求抗反射膜的厚度須 為多少？', '["90nm", "100nm", "125nm", "500nm"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "b457f6524dd3", "answer_pdf_sha1": "ba1c7467242c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00238', 'optometrist', 'optometrist-moex-114-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '光線透過傳統球面鏡片時，會有球面像差情形，當看物體時會有扭曲變形的現象，而非球面鏡片則是減少 鏡片周圍扭曲與變形的程度，將鏡片邊緣像差減到最低，下列關於非球面設計之敘述，何者錯誤？', '["當表面P值為-3.0時，代表鏡片為雙曲線表面", "球面鏡片的基弧變平坦，將導致斜散光差增加，使周邊光學品質下降", "非球面表面具有相同的曲率半徑", "對於球面基弧的鏡片，正度數越高，將導致基弧越陡峭"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "b457f6524dd3", "answer_pdf_sha1": "ba1c7467242c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00239', 'optometrist', 'optometrist-moex-114-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '患者目前配戴雙光鏡片要重配一支新的雙光眼鏡，因為很滿意原來的子片設定希望子片位置維持原來的位 置，他挑選一副新的眼鏡，舊眼鏡的尺寸50□18，B尺寸47，新眼鏡的尺寸52□16，B尺寸49，舊框設 定患者眼睛的下眼瞼到子片的距離為-3mm，新框的下眼瞼到下半鏡圈的距離為26mm，新舊子片要相符 合時，新眼鏡子片高度（Segheight）要多少才適合？', '["23mm", "29mm", "26.5mm", "27.5mm"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "b457f6524dd3", "answer_pdf_sha1": "ba1c7467242c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00240', 'optometrist', 'optometrist-moex-114-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '在工廠指定稜鏡方向時可以使用360度系統與180度系統，下列比較何者錯誤？', '["當從正面觀看透鏡（凸面朝向觀察者）時，左眼基底朝右時360度系統會表示為180度", "360度系統的「基底90」等同於180度系統的「基底90向上」", "360度系統使用0到360度，而180度系統僅使用0到180度", "360度系統直接使用度數指定方向，而180度系統需要在度數後加上「向上」或「向下」來區分"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "b457f6524dd3", "answer_pdf_sha1": "ba1c7467242c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00241', 'optometrist', 'optometrist-moex-114-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '某一子片雙光鏡片，使用驗度儀測量出遠用前頂點度數為+6.01D，遠用後頂點度數+6.22D，近用前頂點 度數為+9.00，鏡片袋上還標註標稱度數（nominalpower）為+6.00D，F=+8.00D，F=-2.00D，t=5mm，', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "b457f6524dd3", "answer_pdf_sha1": "ba1c7467242c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 39, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00242', 'optometrist', 'optometrist-moex-114-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '2 n=1.523，近用加入度部分被髒污給遮住，近用加入度為多少？', '["+2.99D", "+3.00D", "+2.78D", "+1.00D"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "b457f6524dd3", "answer_pdf_sha1": "ba1c7467242c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00243', 'optometrist', 'optometrist-moex-114-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '塑膠鏡架張幅過小時，下列何者無法解決？', '["查看鏡片是否在鏡架顳側溝槽內", "銼磨與前框接合之鏡腳", "將隱藏式鉸鍊插入於前框更深處", "在鏡腳距離端片約3/4英吋處朝外彎折鏡腳"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "b457f6524dd3", "answer_pdf_sha1": "ba1c7467242c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "109", "s": "0904", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
